      } else if (msg.type === 'user') {
        var userContent = msg.content ? msg.content : [];
        for (var k = 0; k < userContent.length; k++) {
          var ublock = userContent[k];
          if (ublock.type === 'tool_result') {
            lines.push('[result: ' + ublock.tool_use_id + ']');
          }
        }
      }
