521	      { type: 'text', text: 'Hello' },
522	    ];
523	    const emptyIterable: AsyncIterable<SessionChunk> = {
524	      [Symbol.asyncIterator]() {
525	        return { async next() { return { value: undefined as unknown as SessionChunk, done: true }; } };
526	      },
527	    };
528	    setGuild(makeGuild({
529	      sessions: { 'ses-run': { id: 'ses-run', status: 'running' } },
530	      transcripts: {},
531	      sessionSubscription: emptyIterable,
532	    }));
533	    const { ctx, jsonResponse, jsonStatus } = makeSSEContextWithQuery({ sessionId: 'ses-run' });
534	    let threw = false;
535	    try {
536	      await spiderRoutes[2].handler(ctx as Parameters<typeof spiderRoutes[2]['handler']>[0]);
537	    } catch {
538	      threw = true;
539	    }
540	    assert.equal(jsonStatus(), 200, 'should not have returned a JSON error');
541	    void chunks; // referenced to satisfy linter
542	    assert.equal(threw || jsonResponse() === undefined, true);
543	  });
544	
545	  it('calls streamSSE with noStream for running session with no broadcaster', async () => {
546	    // sessionSubscription: null means animator.subscribeToSession returns null
547	    setGuild(makeGuild({
548	      sessions: { 'ses-orphan': { id: 'ses-orphan', status: 'running' } },
549	      transcripts: {},
550	      sessionSubscription: null,
551	    }));
552	    const { ctx, jsonResponse, jsonStatus } = makeSSEContextWithQuery({ sessionId: 'ses-orphan' });
553	    let threw = false;
554	    try {
555	      await spiderRoutes[2].handler(ctx as Parameters<typeof spiderRoutes[2]['handler']>[0]);
556	    } catch {
557	      threw = true;
558	    }
559	    assert.equal(jsonStatus(), 200, 'should not have returned a JSON error');
560	    assert.equal(threw || jsonResponse() === undefined, true);
561	  });
