1	/**
2	 * Spider UI — static asset regression tests.
3	 *
4	 * These tests verify the HTML structure generated by spider.js for the rig
5	 * list table.  Because spider.js is a vanilla-JS IIFE (no modules), we
6	 * validate the source text directly to ensure structural invariants hold.
7	 */
8	
9	import { describe, it } from 'node:test';
10	import assert from 'node:assert/strict';
11	import { readFileSync } from 'node:fs';
12	import { resolve, dirname } from 'node:path';
13	import { fileURLToPath } from 'node:url';
14	
15	const __dirname = dirname(fileURLToPath(import.meta.url));
16	const spiderJs = readFileSync(resolve(__dirname, 'spider.js'), 'utf-8');
17	const spiderCss = readFileSync(resolve(__dirname, 'spider.css'), 'utf-8');
18	const indexHtml = readFileSync(resolve(__dirname, 'index.html'), 'utf-8');
19	
20	// ── Rig list row structure ──────────────────────────────────────────────
21	
22	describe('spider.js rig list row HTML', () => {
23	  it('renders the writ-title cell as a rig-link anchor', () => {
24	    // The row template should contain a <td> with a rig-link anchor for the
25	    // writ title (the second <td> in each row).  We match the template
26	    // fragment that builds the writ-title cell.
27	    const writTitleCellPattern =
28	      /<td><a class="rig-link" href="#" data-rig-id="[^"]*"\s*>\s*'\s*\+\s*esc\(writTitle\)/;
29	    assert.match(
30	      spiderJs,
31	      writTitleCellPattern,
32	      'writ-title cell should be a clickable rig-link anchor',
33	    );
34	  });
35	
36	  it('renders the rig-id cell as a rig-link anchor', () => {
37	    const rigIdCellPattern =
38	      /<td><a class="rig-link" href="#" data-rig-id="[^"]*"\s*>\s*'\s*\+\s*esc\(rig\.id\)/;
39	    assert.match(
40	      spiderJs,
41	      rigIdCellPattern,
42	      'rig-id cell should be a clickable rig-link anchor',
43	    );
44	  });
45	
46	  it('writ-title and rig-id cells share the same rig-link class', () => {
47	    // Both cells must use the same class so the click handler wires them
48	    // identically.  Count rig-link anchors in the row template.
49	    const rowTemplateMatch = spiderJs.match(
50	      /var rows = filtered\.map\(function \(rig\) \{[\s\S]*?\.join\(''\)/,
51	    );
52	    assert.ok(rowTemplateMatch, 'should find the row template block');
53	    const rowTemplate = rowTemplateMatch[0];
54	
55	    const rigLinkCount = (rowTemplate.match(/class="rig-link"/g) || []).length;
56	    assert.ok(
57	      rigLinkCount >= 2,
58	      `expected at least 2 rig-link anchors in the row template, found ${rigLinkCount}`,
59	    );
60	  });
61	
62	  it('writ-title cell is NOT rendered as plain text', () => {
63	    // Regression guard: the old pattern was just  '<td>' + esc(writTitle) + '</td>'
64	    // with no anchor.  Ensure that pattern no longer exists.
65	    const plainTitlePattern = /'<td>'\s*\+\s*esc\(writTitle\)\s*\+\s*'<\/td>'/;
66	    assert.doesNotMatch(
67	      spiderJs,
68	      plainTitlePattern,
69	      'writ-title cell must not be rendered as plain (non-linked) text',
70	    );
71	  });
72	});
73	
74	// ── Cancellation UI ──────────────────────────────────────────────────────
75	
76	describe('spider.js cancel button', () => {
77	  it('renders a cancel button with id "cancel-engine-btn"', () => {
78	    assert.match(
79	      spiderJs,
80	      /id="cancel-engine-btn"/,
81	      'should contain a cancel button element',
82	    );
83	  });
84	
85	  it('cancel button has btn--danger class', () => {
86	    assert.match(
87	      spiderJs,
88	      /class="btn btn--danger" id="cancel-engine-btn"/,
89	      'cancel button should have btn--danger class',
90	    );
91	  });
92	
93	  it('cancel button sends POST to /api/rig/cancel', () => {
94	    assert.match(
95	      spiderJs,
96	      /method:\s*'POST'/,
97	      'should use POST method for cancel request',
98	    );
99	    assert.match(
100	      spiderJs,
101	      /\/api\/rig\/cancel/,
102	      'should call the cancel API endpoint',
103	    );
104	  });
105	
106	  it('cancel button is conditional on rig status running or blocked', () => {
107	    assert.match(
108	      spiderJs,
109	      /currentRig\.status === 'running' \|\| currentRig\.status === 'blocked'/,
110	      'showCancel should check for running or blocked rig status',
111	    );
112	  });
113	
114	  it('cancel button is hidden for terminal rig statuses', () => {
115	    assert.match(
116	      spiderJs,
117	      /currentRig\.status === 'cancelled'/,
118	      'should check for cancelled status to hide button',
119	    );
120	  });
121	
122	  it('cancel button does NOT use DELETE method', () => {
123	    // DELETE with JSON body is unreliable across HTTP stacks.
124	    // The cancel fetch must use POST to match the auto-generated tool route.
125	    const cancelFetchBlock = spiderJs.match(
126	      /fetch\('\/api\/rig\/cancel'[\s\S]*?\)/,
127	    );
128	    assert.ok(cancelFetchBlock, 'should find the cancel fetch call');
129	    assert.doesNotMatch(
