147	    );
148	  });
149	
150	  it('cancel handler calls preventDefault on click event', () => {
151	    // The cancel click handler should call e.preventDefault() to guard
152	    // against any default button behaviour.
153	    const cancelHandler = spiderJs.match(
154	      /addEventListener\('click', function \(e\)[\s\S]*?e\.preventDefault\(\)/,
155	    );
156	    assert.ok(
157	      cancelHandler,
158	      'cancel click handler should accept the event and call preventDefault',
159	    );
160	  });
161	});
162	
163	describe('spider.js badgeClass for cancelled', () => {
164	  it('badgeClass returns "badge--cancelled" for cancelled status', () => {
165	    assert.match(
166	      spiderJs,
167	      /case 'cancelled':\s*return 'badge--cancelled'/,
168	      'badgeClass should return badge--cancelled for cancelled status',
169	    );
170	  });
171	
172	  it('cancelled is not grouped with pending in badgeClass', () => {
173	    // Ensure cancelled has its own case, not falling through with pending
