176	      /case 'pending':\s*case 'cancelled'/,
177	      'cancelled should not fall through with pending',
178	    );
179	  });
180	});
181	
182	describe('spider.css cancelled badge styling', () => {
183	  it('contains .badge--cancelled rule', () => {
184	    assert.match(
185	      spiderCss,
